import React from 'react';
import './Resources.css';

const Resources = () => {
  const resources = [
    {
      id: 1,
      title: 'Practice Yoga',
      subtitle: 'The bitter new your resources',
      icon: '🧘‍♀️',
      color: '#dcfce7'
    },
    {
      id: 2,
      title: 'Listen to Music',
      subtitle: 'Cooling waves Perfect to Relaxation',
      icon: '🎵',
      color: '#fed7aa'
    },
    {
      id: 3,
      title: 'Self-Care Tips',
      subtitle: 'More resources take care, of you too!',
      icon: '💜',
      color: '#e0e7ff'
    },
    {
      id: 4,
      title: 'Read Quotes',
      subtitle: 'let all you shared',
      icon: '📖',
      color: '#fef3c7'
    }
  ];

  return (
    <div className="resources">
      <div className="resources-header">
        <h3>Resources</h3>
      </div>
      
      <div className="resources-grid">
        {resources.map((resource) => (
          <div 
            key={resource.id} 
            className="resource-card"
            style={{ backgroundColor: resource.color }}
          >
            <div className="resource-icon">{resource.icon}</div>
            <div className="resource-content">
              <h4 className="resource-title">{resource.title}</h4>
              <p className="resource-subtitle">{resource.subtitle}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Resources;
